/**
 * Unit tests for dependency-confusion-scanner.
 * Verifies it warns (non-blocking) on unclaimed package references, allows the
 * real package, and — unlike content-secret-scanner — scans markdown content
 * (the original Blue Bear finding was in a .md skill rule).
 */

import { describe, it, expect } from 'vitest';
import { dependencyConfusionScanner } from '../../../pretool/write-edit/dependency-confusion-scanner.js';
import type { HookInput } from '../../../types.js';

function writeInput(file_path: string, content: string): HookInput {
  return {
    tool_name: 'Write',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { file_path, content },
  };
}

function editInput(file_path: string, new_string: string): HookInput {
  return {
    tool_name: 'Edit',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { file_path, old_string: 'old', new_string },
  };
}

function context(result: ReturnType<typeof dependencyConfusionScanner>): string {
  return result.hookSpecificOutput?.additionalContext ?? '';
}

describe('dependency-confusion-scanner', () => {
  it('warns (non-blocking) on bare @anthropic-ai/claude in a Write', () => {
    const result = dependencyConfusionScanner(
      writeInput('/app/docs/setup.md', 'Run: npm install @anthropic-ai/claude@latest'),
    );
    expect(result.continue).toBe(true); // warn, never block
    expect(context(result)).toContain('@anthropic-ai/claude');
    expect(context(result)).toContain('@anthropic-ai/claude-code'); // suggests the real pkg
  });

  it('scans markdown (NOT excluded like the secret scanner)', () => {
    const result = dependencyConfusionScanner(
      writeInput('/app/skills/x/rules/y.md', 'npm install @anthropic-ai/claude'),
    );
    expect(context(result)).toContain('Dependency-confusion');
  });

  it('warns on the bug verbatim from the Blue Bear report', () => {
    const result = dependencyConfusionScanner(
      editInput('/app/x.md', 'npm install @anthropic-ai/claude@latest'),
    );
    expect(context(result)).not.toBe('');
  });

  it('allows the real package @anthropic-ai/claude-code', () => {
    const result = dependencyConfusionScanner(
      writeInput('/app/x.md', 'npm install @anthropic-ai/claude-code@latest'),
    );
    expect(context(result)).toBe('');
  });

  it('allows @anthropic-ai/claude-agent-sdk', () => {
    const result = dependencyConfusionScanner(
      writeInput('/app/x.md', 'npm install @anthropic-ai/claude-agent-sdk'),
    );
    expect(context(result)).toBe('');
  });

  it('is silent on unrelated content', () => {
    const result = dependencyConfusionScanner(
      writeInput('/app/x.ts', 'export const add = (a: number, b: number) => a + b;'),
    );
    expect(context(result)).toBe('');
  });

  it('is silent on empty content', () => {
    const result = dependencyConfusionScanner(writeInput('/app/x.md', ''));
    expect(context(result)).toBe('');
  });
});
